        double d = pow(4/3.0*3.141593*4*4*4+4/3.0*3.141593*10*10*10,1.0/3);
        cout<<int(d)<<endl;
    } else if (T == 14) {
        int a,b,c=110;
        a=110;
        b=10;
        for(int i=0;i<110;i=i+1) {
            a=a-1;
            b=b+1;
            if (a*b==3500){
                if(c>a){
                    c = a;
                }
